\begin{aligned}         TTc_ \bullet ; { \left \{ T \beta \right \} } ; { \left \{ \beta \right \} }         & =
     T { \left ( Tc_ \bullet ; { \left \{ \beta \right \} } \right )} ; { \left \{ \beta \right \} }          \\         & =
     T { \left ( \alpha _{X_ \bullet };c_ \bullet \right )} ; { \left \{ \beta \right \} }          \\         & =
     T \alpha _{X_ \bullet };Tc_ \bullet ; { \left \{ \beta \right \} }          \\         & =
     T \alpha _{X_ \bullet }; \alpha _{X_ \bullet };c_ \bullet          \\         & =
      \mu _{UX_ \bullet };
      \alpha _{X_ \bullet };
     c_ \bullet          \\         & =
      \mu _{UX_ \bullet };Tc_ \bullet ; { \left \{ \beta \right \} }        \end{aligned}

